function makeTemplate(
  id: string,
  title: string,
  category: TemplateCategoryId,
  body: string,
  regionIds: string[],
): ColoringTemplate {
  const svg = `<svg viewBox="0 0 400 400" role="img" aria-label="${title}" xmlns="http://www.w3.org/2000/svg">
    <rect width="400" height="400" fill="#fffdf8"/>
    <g stroke="#202020" stroke-width="6" stroke-linejoin="round" stroke-linecap="round">
      ${body}
    </g>
  </svg>`;

  return {
    id,
    title,
    category,
    sourceType: "svg",
    thumbnail: svg,
    svg,
    suggestedColors: basicPalette,
    regionIds,
  };
}

function makeDetailedTemplate(
  id: string,
  title: string,
  category: TemplateCategoryId,
  body: string,
): ColoringTemplate {
  const regionIds = Array.from(body.matchAll(/data-region-id="([^"]+)"/g), (match) => match[1]);
  return makeTemplate(id, title, category, body, regionIds);
}

